import type {
    IAutoCompleteElement,
    ICascadeSelect,
    IContextValues,
    IDropdownSelect,
    IListBoxSelect,
    IMultiSelect,
    ISelectElement,
    ISelectType, ITreeItem,
    ITreeSelect,
} from "@lmb-it/kitsconcerto-types";
import React, {createContext, useCallback, useContext, useEffect, useImperativeHandle, useState,} from "react";
import {arrayType, checkKeys, reMapping} from "./helper";
import Dropdown from "./Dropdown";
import KitsMultiSelect from "./MultiSelect";
import KitsAutoComplete from "./AutoComplete";
import KitsTreeSelect from "./TreeSelect";
import ListBox from "./ListBox";
import KitsCascadeSelect from "./CascadeSelect";

const IFormSelectContext = createContext<IContextValues>({} as IContextValues);



const FormSelect = ({ref, ...props}: ISelectElement & ISelectType) => {
    const [selectedValue, setSelectedValue] = useState<any>(null);
    const [rendererList, setData] = useState<ITreeItem<any>[]>([]);

    const {
        withFilter = false,
        shape = "dropdown",
        list,
        onChange,
        labelKey = "label",
        valueKey = "value",
        outputValueKey = "*",
        childrenKey,
        filterBy,
        hideError,
        value,
    } = props;

    const isMultiple = "isMultiple" in props && props.isMultiple;

    const isAutocompleteComponent = shape == "autocomplete";
    const isListBoxComponent = shape == "listBox";
    const isDropdownComponent = shape == "dropdown";
    const isMultiSelectComponent = shape == "multiselect";
    const isCascadeSelectComponent = shape == "cascade";
    const isTreeSelectComponent = shape == "treeSelect";

    const onItemChange = (e: any, item: any = undefined) => {
        onChange && onChange(e, item);
        // Handle both PrimeReact web (e.target.value) and native (e.value) event formats
        const val = e?.target?.value ?? e?.value;
        if (val !== undefined) {
            setSelectedValue(val);
        }
    };
    // const isArrayOfStrings = Array.isArray(list) && list.every(c => typeof c === 'string')

    const bookTheList = (newList: any[]) => {
        checkKeys(newList, labelKey, valueKey);
        const mapped = reMapping(newList, 0, labelKey, valueKey, childrenKey);
        // Only update state if the mapped result actually changed.
        // reMapping always creates new objects, so we deep-compare to avoid
        // unnecessary re-renders that break AutoComplete focus.
        setData(prev => {
            if (JSON.stringify(prev) === JSON.stringify(mapped)) return prev;
            return mapped;
        });
    };

    const getData = useCallback(() => {
        if (typeof list === "function") {
            list().then((res) => {
                if (res.success && res.data) {
                    bookTheList(res.data);
                }
            });
        } else {
            if (list) {
                bookTheList(list);
            }
        }
    }, [list]);

    useEffect(() => {
        getData();
    }, [list]);

    useEffect(() => {
        setSelectedValue(value);
    }, [value]);

    useImperativeHandle(
        ref,
        () => ({
            value: selectedValue,
            setValue: setSelectedValue,
            focus: () => {
            },
        }),
        [],
    );

    return (
        <IFormSelectContext.Provider
            value={{
                onChange: onItemChange,
                selectedValue,
                list: rendererList,
                labelKey,
                valueKey,
                outputValueKey,
                hideError,
                childrenKey: childrenKey ? childrenKey : (arrayType(list) == 1 ? "children" : ""),
            }}
        >
            {isAutocompleteComponent && (
                <KitsAutoComplete
                    isMultiple={isMultiple}
                    withFilter={withFilter}
                    filterBy={filterBy}
                    {...(props as IAutoCompleteElement)}
                />
            )}
            {isListBoxComponent && (
                <ListBox
                    ref={ref}
                    withFilter={withFilter}
                    filterBy={filterBy}
                    {...(props as IListBoxSelect)}
                />
            )}
            {isDropdownComponent && (
                <Dropdown
                    withFilter={withFilter}
                    filterBy={filterBy}
                    {...(props as IDropdownSelect)}
                />
            )}
            {isMultiSelectComponent && (
                <KitsMultiSelect
                    withFilter={withFilter}
                    filterBy={filterBy}
                    {...(props as IMultiSelect)}
                />
            )}
            {isCascadeSelectComponent && (
                <KitsCascadeSelect
                    withFilter={withFilter}
                    filterBy={filterBy}
                    {...(props as ICascadeSelect)}
                />
            )}
            {isTreeSelectComponent && (
                <KitsTreeSelect
                    withFilter={withFilter}
                    filterBy={filterBy}
                    {...(props as ITreeSelect)}
                />
            )}
        </IFormSelectContext.Provider>
    );
};

export const useSelect = () => useContext(IFormSelectContext);

export default FormSelect;
